def detect_concurrent_overlap(response):
    trace = response.get('trace', [])
    step_names = []

    for step in trace:
        if 'orchestration' in step:
            step_names.append(step['orchestration'].get('step', 'unknown'))

    # Detect coordination patterns indicating multi-agent overlap
    conflict_patterns = [
        ['actionGroup1', 'actionGroup2'],
        ['retrieve', 'actionGroup'],
        ['generate', 'orchestrate']
    ]

    for pattern in conflict_patterns:
        if all(p in step_names for p in pattern):
            print(f"CONCURRENT OVERLAP: {pattern} in trace")
            return True

    return False

