def synchronize_traces(session_id, traces):
    merged_trace = []
    seen_steps = set()

    for trace in traces:
        for step in trace.get('trace', []):
            step_id = step.get('stepId', 'unknown')
            if step_id not in seen_steps:
                merged_trace.append(step)
                seen_steps.add(step_id)

    # Update session with synchronized trace
    bedrock.invoke_agent(
        agentId='your-agent-id',
        agentAliasId='your-alias',
        sessionId=session_id,
        inputText='',
        sessionState={
            'sessionAttributes': {
                'traceSynced': True,
                'traceLength': len(merged_trace)
            }
        }
    )

    return {'trace': merged_trace}
